#!/usr/bin/env node
/**
 * Session Analytics Tool
 * Parse and analyze session history and execution logs
 * Run with: npx tsx src/cli/session_analytics.ts [options]
 */

import fs from "node:fs/promises";
import path from "node:path";
import { performance } from "node:perf_hooks";

interface SessionStats {
  sessionId: string;
  timestamp: number;
  duration?: number;
  messageCount: number;
  userMessages: number;
  assistantMessages: number;
  toolCalls: number;
  toolTypes: Map<string, number>;
  totalTokens?: number;
}

interface ExecutionStats {
  logId: string;
  timestamp: number;
  exitCode: number;
  duration: number;
  size: number;
  errorCount: number;
  warningCount: number;
}

interface AnalyticsReport {
  totalSessions: number;
  totalExecutions: number;
  totalMessages: number;
  totalToolCalls: number;
  avgMessagesPerSession: number;
  avgSessionDuration: number;
  mostUsedTools: Array<[string, number]>;
  sessionTrends: Array<{ date: string; count: number }>;
  toolUsageDistribution: Map<string, number>;
  errorsBySession: Map<string, number>;
  sessions: SessionStats[];
  executions: ExecutionStats[];
}

function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

async function parseSessionFile(filepath: string): Promise<SessionStats | null> {
  try {
    const content = await fs.readFile(filepath, "utf-8");
    const session = JSON.parse(content);

    if (!Array.isArray(session)) {
      return null;
    }

    const filename = path.basename(filepath);
    const timestamp = parseInt(filename.match(/session_(\d+)\.json/)?.[1] || "0");

    let messageCount = 0;
    let userMessages = 0;
    let assistantMessages = 0;
    let toolCalls = 0;
    let totalTokens = 0;
    const toolTypes = new Map<string, number>();

    for (const msg of session) {
      if (msg.role) {
        messageCount++;

        // Count by role
        if (msg.role === "user") userMessages++;
        else if (msg.role === "assistant") assistantMessages++;

        // Count tool calls
        if (msg.tool_calls) {
          toolCalls += msg.tool_calls.length;
          for (const tc of msg.tool_calls) {
            const toolName = tc?.function?.name || "unknown";
            toolTypes.set(toolName, (toolTypes.get(toolName) || 0) + 1);
          }
        }

        // Estimate tokens
        const content = msg.content || msg.reasoning_content || "";
        totalTokens += estimateTokens(typeof content === "string" ? content : JSON.stringify(content));
      }
    }

    return {
      sessionId: filename,
      timestamp,
      messageCount,
      userMessages,
      assistantMessages,
      toolCalls,
      toolTypes,
      totalTokens
    };
  } catch (e) {
    return null;
  }
}

async function parseExecutionLog(filepath: string): Promise<ExecutionStats | null> {
  try {
    const content = await fs.readFile(filepath, "utf-8");
    const filename = path.basename(filepath);
    const timestamp = parseInt(filename.match(/execution_(\d+)\.log/)?.[1] || "0");

    const lines = content.split("\n");
    let exitCode = 0;
    let duration = 0;
    let errorCount = 0;
    let warningCount = 0;

    for (const line of lines) {
      if (line.includes("Exited with code")) {
        const match = line.match(/code (-?\d+)/);
        if (match) exitCode = parseInt(match[1]);
      }
      if (line.includes("after")) {
        const match = line.match(/after (\d+)s/);
        if (match) duration = parseInt(match[1]);
      }
      if (line.toLowerCase().includes("error") || line.includes("✗ FAIL")) {
        errorCount++;
      }
      if (line.toLowerCase().includes("warning")) {
        warningCount++;
      }
    }

    return {
      logId: filename,
      timestamp,
      exitCode,
      duration,
      size: content.length,
      errorCount,
      warningCount
    };
  } catch (e) {
    return null;
  }
}

async function loadSessions(): Promise<SessionStats[]> {
  const historyDir = path.join(process.cwd(), "history");
  const sessions: SessionStats[] = [];

  try {
    const files = await fs.readdir(historyDir);
    const sessionFiles = files.filter(f => f.startsWith("session_") && f.endsWith(".json"));

    for (const file of sessionFiles) {
      const stats = await parseSessionFile(path.join(historyDir, file));
      if (stats) sessions.push(stats);
    }
  } catch (e) {
    // Ignore errors for missing directory
  }

  return sessions.sort((a, b) => a.timestamp - b.timestamp);
}

async function loadExecutions(): Promise<ExecutionStats[]> {
  const logsDir = path.join(process.cwd(), "logs");
  const executions: ExecutionStats[] = [];

  try {
    const files = await fs.readdir(logsDir);
    const logFiles = files.filter(f => f.startsWith("execution_") && f.endsWith(".log"));

    for (const file of logFiles) {
      const stats = await parseExecutionLog(path.join(logsDir, file));
      if (stats) executions.push(stats);
    }
  } catch (e) {
    // Ignore errors
  }

  return executions.sort((a, b) => a.timestamp - b.timestamp);
}

function generateReport(sessions: SessionStats[], executions: ExecutionStats[]): AnalyticsReport {
  // Aggregate tool usage
  const toolUsage = new Map<string, number>();
  for (const session of sessions) {
    for (const [tool, count] of session.toolTypes) {
      toolUsage.set(tool, (toolUsage.get(tool) || 0) + count);
    }
  }

  // Calculate trends by date
  const dateCounts = new Map<string, number>();
  for (const session of sessions) {
    const date = new Date(session.timestamp).toISOString().split("T")[0]!;
    dateCounts.set(date, (dateCounts.get(date) || 0) + 1);
  }

  const trends = Array.from(dateCounts.entries())
    .sort((a, b) => a[0].localeCompare(b[0]))
    .map(([date, count]) => ({ date, count }));

  // Most used tools
  const mostUsedTools = Array.from(toolUsage.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10);

  // Calculate averages
  const totalMessages = sessions.reduce((sum, s) => sum + s.messageCount, 0);
  const totalToolCalls = sessions.reduce((sum, s) => sum + s.toolCalls, 0);
  const avgMessages = sessions.length > 0 ? totalMessages / sessions.length : 0;
  const avgDuration = executions.length > 0 
    ? executions.reduce((sum, e) => sum + e.duration, 0) / executions.length 
    : 0;

  // Errors by session (checkpoint)
  const errorsBySession = new Map<string, number>();
  for (const exec of executions) {
    if (exec.errorCount > 0) {
      errorsBySession.set(exec.logId, exec.errorCount);
    }
  }

  return {
    totalSessions: sessions.length,
    totalExecutions: executions.length,
    totalMessages,
    totalToolCalls,
    avgMessagesPerSession: avgMessages,
    avgSessionDuration: avgDuration,
    mostUsedTools,
    sessionTrends: trends,
    toolUsageDistribution: toolUsage,
    errorsBySession,
    sessions,
    executions
  };
}

function renderHistogram(data: Array<{ date: string; count: number }>, width: number = 50): string {
  if (data.length === 0) return "No data available\n";

  const maxCount = Math.max(...data.map(d => d.count));
  const lines: string[] = [];

  for (const item of data) {
    const barLength = maxCount > 0 
      ? Math.round((item.count / maxCount) * width) 
      : 0;
    const bar = "█".repeat(barLength);
    const label = item.date.substring(5); // MM-DD
    lines.push(`${label} │${bar.padEnd(width)} ${item.count}`);
  }

  return lines.join("\n");
}

function renderToolChart(tools: Array<[string, number]>, width: number = 40): string {
  if (tools.length === 0) return "No tool usage data\n";

  const maxCount = Math.max(...tools.map(([, count]) => count));
  const lines: string[] = [];

  for (const [name, count] of tools) {
    const barLength = maxCount > 0 
      ? Math.round((count / maxCount) * width) 
      : 0;
    const bar = "▓".repeat(barLength);
    const shortName = name.length > 20 ? name.substring(0, 17) + "..." : name.padEnd(20);
    lines.push(`${shortName} │${bar} ${count}`);
  }

  return lines.join("\n");
}

function formatBytes(bytes: number): string {
  if (bytes < 1024) return `${bytes}B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)}KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)}MB`;
}

function formatDuration(seconds: number): string {
  if (seconds < 60) return `${seconds}s`;
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ${seconds % 60}s`;
  return `${Math.floor(seconds / 3600)}h ${Math.floor((seconds % 3600) / 60)}m`;
}

async function saveReport(report: AnalyticsReport, outputDir: string) {
  await fs.mkdir(outputDir, { recursive: true);

  const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
  const reportPath = path.join(outputDir, `analytics_${timestamp}.json`);

  // Convert Maps to objects for JSON
  const jsonReport = {
    ...report,
    toolUsageDistribution: Object.fromEntries(report.toolUsageDistribution),
    errorsBySession: Object.fromEntries(report.errorsBySession),
    sessions: report.sessions.map(s => ({
      ...s,
      toolTypes: Object.fromEntries(s.toolTypes)
    })),
    generatedAt: new Date().toISOString()
  };

  await fs.writeFile(reportPath, JSON.stringify(jsonReport, null, 2));
  return reportPath;
}

async function main() {
  const startTime = performance.now();
  const args = process.argv.slice(2);
  const verbose = args.includes("--verbose") || args.includes("-v");
  const exportJson = args.includes("--json") || args.includes("-j");

  console.log("╔══════════════════════════════════════════════════════════╗");
  console.log("║          SESSION ANALYTICS DASHBOARD                     ║");
  console.log("║          Memory & Execution Analysis                       ║");
  console.log("╚══════════════════════════════════════════════════════════╝");

  console.log("\n[LOAD] Processing session files...");
  const sessions = await loadSessions();

  console.log("[LOAD] Processing execution logs...");
  const executions = await loadExecutions();

  console.log(`[Loaded] ${sessions.length} sessions, ${executions.length} executions`);

  const report = generateReport(sessions, executions);

  // Summary
  console.log("\n" + "═".repeat(60));
  console.log("                     SUMMARY");
  console.log("═".repeat(60));
  console.log(`Total Sessions:          ${report.totalSessions.toLocaleString()}`);
  console.log(`Total Executions:        ${report.totalExecutions.toLocaleString()}`);
  console.log(`Total Messages:          ${report.totalMessages.toLocaleString()}`);
  console.log(`Total Tool Calls:        ${report.totalToolCalls.toLocaleString()}`);
  console.log(`Avg Messages/Session:    ${report.avgMessagesPerSession.toFixed(1)}`);
  console.log(`Avg Execution Duration:  ${formatDuration(report.avgSessionDuration)}`);

  if (report.totalToolCalls > 0) {
    console.log("\n" + "═".repeat(60));
    console.log("                  TOOL USAGE");
    console.log("═".repeat(60));
    console.log(renderToolChart(report.mostUsedTools));
  }

  if (report.sessionTrends.length > 0) {
    console.log("\n" + "═".repeat(60));
    console.log("              SESSION TRENDS (Last 14 Days)");
    console.log("═".repeat(60));
    const recentTrends = report.sessionTrends.slice(-14);
    console.log(renderHistogram(recentTrends));
  }

  if (verbose) {
    console.log("\n" + "═".repeat(60));
    console.log("              RECENT SESSIONS");
    console.log("═".repeat(60));
    const recentSessions = report.sessions.slice(-5).reverse();
    for (const s of recentSessions) {
      console.log(`\n${s.sessionId}:`);
      console.log(`  Messages: ${s.messageCount} (${s.userMessages} user, ${s.assistantMessages} assistant)`);
      console.log(`  Tools: ${s.toolCalls}`);
      if (s.totalTokens) {
        console.log(`  Est. Tokens: ${s.totalTokens.toLocaleString()}`);
      }
    }
  }

  if (exportJson) {
    const outputDir = path.join(process.cwd(), "logs", "analytics");
    const reportPath = await saveReport(report, outputDir);
    console.log(`\n[EXPORT] Report saved to: ${reportPath}`);
  }

  const duration = performance.now() - startTime;
  console.log(`\n[ANALYTICS] Completed in ${duration.toFixed(2)}ms`);
}

main().catch(err => {
  console.error("[ERROR] Analytics failed:", err);
  process.exit(1);
});
